const body = $('Webhook').item.json.body || {};
const mode = body.mode || 'A';
const message = body.message || '';
const history = body.history || '';
let sessionId = body.session_id;
if (sessionId === undefined || sessionId === null || sessionId === '') {
  sessionId = 'scout-' + Date.now() + '-' + Math.random().toString(36).slice(2, 10);
}
const userId = $('Fetch User').item.json.user_id;
const clientId = $('Fetch User').item.json.client_id;

// --- Company profile the user already gave during the brand interview ---
const pc = body.profile_context || {};
const summary = pc.profile_summary || pc;
function arr(v) { return Array.isArray(v) ? v.filter(Boolean) : (v ? [v] : []); }
const pName = summary.name || '';
const pIndustry = summary.industry || '';
const pTagline = summary.tagline || '';
const pAudience = summary.audience || '';
const pTone = arr(summary.tone_keywords);
const pTypes = arr(summary.content_types);
const recsSrc = pc.recommendations || (pc.website_scan && pc.website_scan.recommendations) || [];
const recs = arr(recsSrc);
const hasProfile = (pName || pIndustry || pAudience) ? true : false;

let profileBlock = 'No company profile on file yet — ask a little more before curating.';
if (hasProfile) {
  const lines = [];
  if (pName) lines.push('Company: ' + pName);
  if (pIndustry) lines.push('Industry: ' + pIndustry);
  if (pTagline) lines.push('Tagline: ' + pTagline);
  if (pAudience) lines.push('Audience: ' + pAudience);
  if (pTone.length) lines.push('Tone: ' + pTone.join(', '));
  if (pTypes.length) lines.push('Content they make: ' + pTypes.join(', '));
  if (recs.length) {
    const r = recs.slice(0, 5).map(function (x) {
      return '- ' + (x.topic || x.format || '') + (x.reason ? ' (' + x.reason + ')' : '');
    }).join('\n');
    lines.push('Ideas already surfaced from their website scan:\n' + r);
  }
  profileBlock = lines.join('\n');
}

// --- Existing radar state ---
let priorities = $('Read Priorities').first().json.markdown || '';
if (priorities === '' && hasProfile) {
  priorities = [
    '## What they do',
    (pName ? pName + ' — ' : '') + (pTagline || pIndustry || ''),
    '',
    '## Who it is for',
    pAudience || '',
    '',
    '## Voice',
    pTone.length ? pTone.join(', ') : '',
    '',
    '## Content they make',
    pTypes.length ? pTypes.join(', ') : ''
  ].join('\n');
}

const allSources = $('Read Sources').all().map(function (i) { return i.json; });
const followed = allSources.filter(function (s) { return s.status === 'followed'; });
const naylisted = allSources.filter(function (s) { return s.status === 'naylisted'; });
const followedStr = followed.length > 0
  ? followed.map(function (s) { return '- ' + s.name + ' (' + s.url + ') [' + (s.category || 'uncategorized') + ']'; }).join('\n')
  : 'None';
const naylistedStr = naylisted.length > 0
  ? naylisted.map(function (s) { return '- ' + s.name + ' (' + s.url + ')'; }).join('\n')
  : 'None';

// --- Turn budget + "just go" escape hatch ---
const priorUserTurns = (history.match(/\[user\]/g) || []).length;
const turnCount = priorUserTurns + 1;
const maxTurns = 2;
const justGo = /(\bjust go\b|\bgo ahead\b|\bfind them\b|\bfind sources\b|ga maar|ga door|begin maar|zoek maar|vind ze|vind bronnen|doe maar|laat maar|\bskip\b|sla over|start maar)/i.test(message);
const forceClose = (justGo || turnCount >= maxTurns) ? true : false;

let closeDirective;
if (forceClose) {
  closeDirective = 'THIS IS THE FINAL TURN. Do not ask another question. Output the exact close line, set done=true, and produce the priorities doc plus a generous set of source suggestions now.';
} else {
  closeDirective = 'You may ask ONE short refining question if it would materially improve the source picks. Otherwise close now. Budget: at most ' + maxTurns + ' user turns; this is turn ' + turnCount + '.';
}

return [{ json: {
  query: message ? message : '(the user opened Scout without typing yet — greet them using what you know and ask your one question)',
  sessionId: sessionId,
  userId: userId,
  clientId: clientId,
  mode: mode,
  profileBlock: profileBlock,
  priorities: priorities,
  followedSources: followedStr,
  naylistedSources: naylistedStr,
  followedCount: followed.length,
  naylistedCount: naylisted.length,
  history: history,
  turnCount: turnCount,
  forceClose: forceClose,
  closeDirective: closeDirective
}}];

let raw = $input.first().json.output;
const sessionId = $('Build Prompt').first().json.sessionId;
const userId = $('Build Prompt').first().json.userId;
const clientId = $('Build Prompt').first().json.clientId;
const forceClose = $('Build Prompt').first().json.forceClose === true;

const CLOSE_LINE = 'go look for the voices you should be listening to';

let parsed = null;
if (typeof raw === 'object' && raw !== null) {
  parsed = raw;
} else {
  let text = String(raw || '').trim();
  text = text.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?\s*```\s*$/, '').trim();
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    const match = text.match(/\{[\s\S]*\}/);
    if (match) {
      try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = null; }
    }
  }
  if (parsed === null) {
    // Could not parse JSON (often a truncated closing payload). Recover the message and detect the close.
    const rawText = String(raw || '');
    const closing = (rawText.indexOf(CLOSE_LINE) >= 0) || forceClose;
    let msg = '';
    const mm = rawText.match(/"message"\s*:\s*"((?:[^"\\]|\\.)*)"/);
    if (mm) { try { msg = JSON.parse('"' + mm[1] + '"'); } catch (e3) { msg = mm[1]; } }
    if (msg === '') msg = rawText.replace(/```[\s\S]*$/, '').replace(/\{[\s\S]*$/, '').trim();
    if (msg === '' || msg.charAt(0) === '{') msg = 'Een moment, ik zet je Radar klaar.';
    parsed = { message: msg, done: closing, priorities: null, sources: [] };
  }
}

let message = parsed.message || String(raw);
let done = parsed.done === true;
const priorities = parsed.priorities || null;
const sources = Array.isArray(parsed.sources) ? parsed.sources : [];

// Safety net: if the close line was emitted, treat as done even if the flag was dropped.
if (done === false && typeof message === 'string' && message.indexOf(CLOSE_LINE) >= 0) {
  done = true;
}

return [{ json: {
  message: message,
  done: done,
  priorities: priorities,
  sources: sources,
  sessionId: sessionId,
  userId: userId,
  clientId: clientId
}}];

return [{ json: {
  session_id: $json.sessionId,
  message: $json.message,
  done: false,
  events: []
}}];

const priorities = $json.priorities || '';
const rawSources = $json.sources || [];
const userId = $json.userId;
const clientId = $json.clientId;
const sessionId = $json.sessionId;
const message = $json.message;

// Dedupe only true duplicates (same URL). A site may legitimately appear several times with
// different URLs: a business vs consumer section, or two products each with their own blog.
const seen = {};
const sources = [];
for (const s of rawSources) {
  const key = ((s.url || s.name || '') + '').trim().toLowerCase()
    .replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/+$/, '');
  if (key === '' || seen[key] === true) continue;
  seen[key] = true;
  sources.push(s);
}

const escapedPriorities = priorities.replace(/'/g, "''");

const prioritiesQuery = priorities
  ? `UPDATE portal_user SET settings = jsonb_set(jsonb_set(COALESCE(settings, '{}'), '{radar}', COALESCE(settings->'radar', '{}')), '{radar,priorities_markdown}', to_jsonb('${escapedPriorities}'::text)) WHERE n8n_user_id = '${userId}'::uuid`
  : 'SELECT 1';

let sourcesQuery = 'SELECT 1 WHERE false';
if (sources.length > 0) {
  const values = sources.map(s => {
    const esc = v => (v || '').replace(/'/g, "''");
    return `('${userId}'::uuid, '${esc(clientId)}', '${esc(s.url)}', '${esc(s.name)}', '${esc(s.category)}', '${esc(s.tone_tag)}', '${esc(s.because_quote)}', 'proposed', 'unknown')`;
  }).join(', ');
  sourcesQuery = `INSERT INTO radar_sources (user_id, client_id, url, name, category, tone_tag, because_quote, status, viability) VALUES ${values}`;
}

const events = [];
if (priorities) events.push({ type: 'tool_call', name: 'updatePriorities', args: {} });
sources.forEach(s => events.push({ type: 'tool_call', name: 'proposeSource', args: { name: s.name, url: s.url } }));

return [{ json: { prioritiesQuery, sourcesQuery, message, sessionId, events } }];

const prev = $('Prepare Curation').first().json;
return [{ json: {
  session_id: prev.sessionId,
  message: prev.message,
  done: true,
  events: prev.events
}}];

